     1→import express from "express";
     2→import cors from "cors";
     3→import { WebSocketServer, WebSocket } from "ws";
     4→import { createServer } from "http";
     5→import { execSync } from "child_process";
     6→import { existsSync } from "fs";
     7→import { getDb } from "./db.js";
     8→import { indexAllCheckpoints, indexAllCheckpointsV2 } from "./indexer.js";
     9→
    10→// ─── Response types ───────────────────────────────────────────────────────────
    11→
    12→interface SessionResponse {
    13→  sessionId: string;
    14→  startedAt: string;
    15→  updatedAt: string;
    16→  cwd: string;
    17→  repoRoot: string | null;
    18→  repoName: string | null;
    19→  parentSessionId: string | null;
    20→  childSessionIds: string[];
    21→  gitUserName: string | null;
    22→  gitUserEmail: string | null;
    23→  prompt: string | null;
    24→  summary: string | null;
    25→  keywords: string[];
    26→  branch: string | null;
    27→  intent: string | null;
    28→}
    29→
    30→interface EventResponse {
    31→  id: number;
    32→  timestamp: string;
    33→  event: string;
    34→  sessionId: string;
    35→  blocked: boolean;
    36→  data: unknown;
    37→  summary: string | null;
    38→  keywords: string[];
    39→}
    40→
    41→interface OverviewResponse {
    42→  sessionId: string;
    43→  summary: string;
    44→  keywords: string[];
    45→  startedAt: string;
    46→  endedAt: string;
    47→}
    48→
    49→// ─── Mapping helpers ──────────────────────────────────────────────────────────
    50→
    51→function mapSummary(s: {
    52→  intent: string;
    53→  outcome: string;
    54→  learningsRepo: string | null;
    55→  learningsCode: string | null;
    56→  learningsWorkflow: string | null;
    57→  friction: string | null;
    58→  openItems: string | null;
    59→}) {
    60→  return {
    61→    intent: s.intent,
    62→    outcome: s.outcome,
    63→    repoLearnings:     s.learningsRepo     ? (JSON.parse(s.learningsRepo)     as string[]) : [],
    64→    codeLearnings:     s.learningsCode     ? (JSON.parse(s.learningsCode)     as Array<{ path: string; finding: string }>) : [],
    65→    workflowLearnings: s.learningsWorkflow ? (JSON.parse(s.learningsWorkflow) as string[]) : [],
    66→    friction:          s.friction          ? (JSON.parse(s.friction)          as string[]) : [],
    67→    openItems:         s.openItems         ? (JSON.parse(s.openItems)         as string[]) : [],
    68→  };
    69→}
    70→
    71→
    72→function mapSession(
    73→  s: {
    74→    sessionId: string;
    75→    startedAt: Date;
    76→    updatedAt: Date;
    77→    cwd: string;
    78→    repoRoot: string | null;
    79→    repoName: string | null;
    80→    parentSessionId: string | null;
    81→    gitUserName: string | null;
    82→    gitUserEmail: string | null;
    83→    prompt: string | null;
    84→    summary: string | null;
    85→    keywords: string | null;
    86→  },
    87→  childSessionIds: string[] = [],
    88→  branch: string | null = null,
    89→  intent: string | null = null,
    90→): SessionResponse {
    91→  return {
    92→    sessionId: s.sessionId,
    93→    startedAt: s.startedAt.toISOString(),
    94→    updatedAt: s.updatedAt.toISOString(),
    95→    cwd: s.cwd,
    96→    repoRoot: s.repoRoot,
    97→    repoName: s.repoName,
    98→    parentSessionId: s.parentSessionId,
    99→    childSessionIds,
   100→    gitUserName: s.gitUserName,
   101→    gitUserEmail: s.gitUserEmail,
   102→    prompt: s.prompt,
   103→    summary: s.summary,
   104→    keywords: s.keywords ? (JSON.parse(s.keywords) as string[]) : [],
   105→    branch,
   106→    intent,
   107→  };
   108→}
   109→
   110→function mapEvent(e: {
   111→  id: number;
   112→  timestamp: Date;
   113→  event: string;
   114→  sessionId: string;
   115→  blocked: boolean;
   116→  data: string;
   117→  summary: string | null;
   118→  keywords: string | null;
   119→}): EventResponse {
   120→  let parsedData: unknown;
   121→  try {
   122→    parsedData = JSON.parse(e.data);
   123→  } catch {
   124→    parsedData = e.data;
   125→  }
   126→  return {
   127→    id: e.id,
   128→    timestamp: e.timestamp.toISOString(),
   129→    event: e.event,
   130→    sessionId: e.sessionId,
   131→    blocked: e.blocked,
   132→    data: parsedData,
   133→    summary: e.summary,
   134→    keywords: e.keywords ? (JSON.parse(e.keywords) as string[]) : [],
   135→  };
   136→}
   137→
   138→// ─── Server ───────────────────────────────────────────────────────────────────
   139→
   140→export async function startServer(dbPath: string, port: number, repoDir?: string): Promise<void> {
   141→  // Strip CLAUDECODE so spawned sessions are not blocked by nested-session detection
   142→  delete process.env.CLAUDECODE;
   143→
   144→  const db = await getDb(dbPath);
   145→
   146→  const app = express();
   147→  app.use(cors());
   148→  app.use(express.json());
   149→
   150→  // GET /api/sessions
   151→  app.get("/api/sessions", async (_req, res) => {
   152→    try {
   153→      const sessions = await db.session.findMany({
   154→        orderBy: { updatedAt: "desc" },
   155→      });
   156→      const sessionIds = sessions.map((s) => s.sessionId);
   157→
   158→      // Fetch latest branch and intent per session from CheckpointSessionMetadata
   159→      const sessionMetas = await db.checkpointSessionMetadata.findMany({
   160→        where: { sessionId: { in: sessionIds } },
   161→        select: { sessionId: true, branch: true, createdAt: true, summary: { select: { intent: true } } },
   162→        orderBy: { createdAt: "desc" },
   163→      });
   164→      const branchMap = new Map<string, string | null>();
   165→      const intentMap = new Map<string, string | null>();
   166→      for (const m of sessionMetas) {
   167→        if (!branchMap.has(m.sessionId)) branchMap.set(m.sessionId, m.branch);
   168→        if (!intentMap.has(m.sessionId)) intentMap.set(m.sessionId, m.summary?.intent ?? null);
   169→      }
   170→
   171→      // Build parent → children map in memory
   172→      const childMap = new Map<string, string[]>();
   173→      for (const s of sessions) {
   174→        if (s.parentSessionId) {
   175→          const arr = childMap.get(s.parentSessionId) ?? [];
   176→          arr.push(s.sessionId);
   177→          childMap.set(s.parentSessionId, arr);
   178→        }
   179→      }
   180→      res.json(sessions.map((s) => mapSession(s, childMap.get(s.sessionId) ?? [], branchMap.get(s.sessionId) ?? null, intentMap.get(s.sessionId) ?? null)));
   181→    } catch (err) {
   182→      res.status(500).json({ error: String(err) });
   183→    }
   184→  });
   185→
   186→  // GET /api/sessions/:id
   187→  app.get("/api/sessions/:id", async (req, res) => {
   188→    try {
   189→      const [session, children, latestMeta] = await Promise.all([
   190→        db.session.findUnique({ where: { sessionId: req.params.id } }),
   191→        db.session.findMany({
   192→          where: { parentSessionId: req.params.id },
   193→          select: { sessionId: true },
   194→        }),
   195→        db.checkpointSessionMetadata.findFirst({
   196→          where: { sessionId: req.params.id },
   197→          select: { branch: true, summary: { select: { intent: true } } },
   198→          orderBy: { createdAt: "desc" },
   199→        }),
   200→      ]);
   201→      if (!session) {
   202→        res.status(404).json({ error: "Session not found" });
   203→        return;
   204→      }
   205→      res.json(mapSession(session, children.map((c) => c.sessionId), latestMeta?.branch ?? null, latestMeta?.summary?.intent ?? null));
   206→    } catch (err) {
   207→      res.status(500).json({ error: String(err) });
   208→    }
   209→  });
   210→
   211→  // GET /api/sessions/:id/overview
   212→  app.get("/api/sessions/:id/overview", async (req, res) => {
   213→    try {
   214→      const overview = await db.interactionOverview.findUnique({
   215→        where: { sessionId: req.params.id },
   216→      });
   217→      if (!overview) {
   218→        res.status(404).json({ error: "No overview for this session" });
   219→        return;
   220→      }
   221→      const result: OverviewResponse = {
   222→        sessionId: overview.sessionId,
   223→        summary: overview.summary,
   224→        keywords: overview.keywords ? (JSON.parse(overview.keywords) as string[]) : [],
   225→        startedAt: overview.startedAt.toISOString(),
   226→        endedAt: overview.endedAt.toISOString(),
   227→      };
   228→      res.json(result);
   229→    } catch (err) {
   230→      res.status(500).json({ error: String(err) });
   231→    }
   232→  });
   233→
   234→  // GET /api/sessions/:id/events
   235→  app.get("/api/sessions/:id/events", async (req, res) => {
   236→    try {
   237→      const events = await db.event.findMany({
   238→        where: { sessionId: req.params.id },
   239→        orderBy: { timestamp: "asc" },
   240→      });
   241→      res.json(events.map(mapEvent));
   242→    } catch (err) {
   243→      res.status(500).json({ error: String(err) });
   244→    }
   245→  });
   246→
   247→  // GET /api/checkpoints
   248→  app.get("/api/checkpoints", async (_req, res) => {
   249→    try {
   250→      const checkpoints = await db.checkpoint.findMany({
   251→        include: {
   252→          sessions: {
   253→            select: { sessionId: true, summary: true },
   254→            orderBy: { sessionIndex: "asc" },
   255→          },
   256→        },
   257→        orderBy: { indexedAt: "desc" },
   258→      });
   259→      res.json(checkpoints.map((c) => {
   260→        const firstSummary = c.sessions.find((s) => s.summary)?.summary ?? null;
   261→        return {
   262→          checkpointId: c.checkpointId,
   263→          branch: c.branch,
   264→          cliVersion: c.cliVersion,
   265→          strategy: c.strategy,
   266→          filesTouched: c.filesTouched ? (JSON.parse(c.filesTouched) as string[]) : [],
   267→          tokenUsage: c.tokenUsage ? (JSON.parse(c.tokenUsage) as Record<string, unknown>) : null,
   268→          indexedAt: c.indexedAt.toISOString(),
   269→          sessionCount: c.sessions.length,
   270→          summary: firstSummary ? mapSummary(firstSummary) : null,
   271→        };
   272→      }));
   273→    } catch (err) {
   274→      res.status(500).json({ error: String(err) });
   275→    }
   276→  });
   277→
   278→  // GET /api/checkpoints/:id
   279→  app.get("/api/checkpoints/:id", async (req, res) => {
   280→    try {
   281→      const checkpoint = await db.checkpoint.findUnique({
   282→        where: { checkpointId: req.params.id },
   283→        include: {
   284→          sessions: {
   285→            include: { summary: true },
   286→            orderBy: { sessionIndex: "asc" },
   287→          },
   288→        },
   289→      });
   290→      if (!checkpoint) { res.status(404).json({ error: "Not found" }); return; }
   291→      res.json({
   292→        checkpointId: checkpoint.checkpointId,
   293→        branch: checkpoint.branch,
   294→        cliVersion: checkpoint.cliVersion,
   295→        strategy: checkpoint.strategy,
   296→        filesTouched: checkpoint.filesTouched ? (JSON.parse(checkpoint.filesTouched) as string[]) : [],
   297→        tokenUsage: checkpoint.tokenUsage ? (JSON.parse(checkpoint.tokenUsage) as Record<string, unknown>) : null,
   298→        indexedAt: checkpoint.indexedAt.toISOString(),
   299→        sessionCount: checkpoint.sessions.length,
   300→        summary: checkpoint.sessions.find((s) => s.summary)?.summary
   301→          ? mapSummary(checkpoint.sessions.find((s) => s.summary)!.summary!)
   302→          : null,
   303→        sessions: checkpoint.sessions.map((s) => ({
   304→          sessionId: s.sessionId,
   305→          sessionIndex: s.sessionIndex,
   306→          agent: s.agent,
   307→          createdAt: s.createdAt?.toISOString() ?? null,
   308→          filesTouched: s.filesTouched ? (JSON.parse(s.filesTouched) as string[]) : [],
   309→          tokenUsage: s.tokenUsage ? (JSON.parse(s.tokenUsage) as Record<string, unknown>) : null,
   310→          summary: s.summary ? mapSummary(s.summary) : null,
   311→        })),
   312→      });
   313→    } catch (err) {
   314→      res.status(500).json({ error: String(err) });
   315→    }
   316→  });
   317→
   318→  // GET /api/sessions/:sessionId/checkpoints
   319→  app.get("/api/sessions/:sessionId/checkpoints", async (req, res) => {
   320→    try {
   321→      const links = await db.checkpointSessionLink.findMany({
   322→        where: { sessionId: req.params.sessionId },
   323→        select: { checkpointId: true },
   324→      });
   325→      if (links.length === 0) { res.json([]); return; }
   326→      const checkpointIds = links.map((l) => l.checkpointId);
   327→      const checkpoints = await db.checkpoint.findMany({
   328→        where: { checkpointId: { in: checkpointIds } },
   329→        include: {
   330→          sessions: {
   331→            where: { sessionId: req.params.sessionId },
   332→            include: { summary: true },
   333→          },
   334→        },
   335→        orderBy: { indexedAt: "asc" },
   336→      });
   337→      res.json(checkpoints.map((c) => {
   338→        const session = c.sessions[0] ?? null;
   339→        return {
   340→          checkpointId: c.checkpointId,
   341→          branch: c.branch,
   342→          cliVersion: c.cliVersion,
   343→          filesTouched: c.filesTouched ? (JSON.parse(c.filesTouched) as string[]) : [],
   344→          tokenUsage: c.tokenUsage ? (() => { const t = JSON.parse(c.tokenUsage) as Record<string, unknown>; return { inputTokens: t.input_tokens, cacheCreationTokens: t.cache_creation_tokens, cacheReadTokens: t.cache_read_tokens, outputTokens: t.output_tokens, apiCallCount: t.api_call_count }; })() : null,
   345→          createdAt: session?.createdAt?.toISOString() ?? null,
   346→          summary: session?.summary ? mapSummary(session.summary) : null,
   347→        };
   348→      }));
   349→    } catch (err) {
   350→      res.status(500).json({ error: String(err) });
   351→    }
   352→  });
   353→
   354→  // GET /api/checkpoints/:id/messages
   355→  app.get("/api/checkpoints/:id/messages", async (req, res) => {
   356→    try {
   357→      const sessions = await db.checkpointSession.findMany({
   358→        where: { checkpointId: req.params.id },
   359→        select: { sessionId: true },
   360→      });
   361→      const sessionIds = sessions.map((s) => s.sessionId);
   362→      if (sessionIds.length === 0) { res.json([]); return; }
   363→      const messages = await db.checkpointMessage.findMany({
   364→        where: { sessionId: { in: sessionIds } },
   365→        orderBy: { timestamp: "asc" },
   366→      });
   367→      res.json(messages.map((m) => ({
   368→        id: m.id,
   369→        uuid: m.uuid,
   370→        sessionId: m.sessionId,
   371→        parentUuid: m.parentUuid,
   372→        type: m.type,
   373→        timestamp: m.timestamp?.toISOString() ?? null,
   374→        gitBranch: m.gitBranch,
   375→        slug: m.slug,
   376→        planContent: m.planContent,
   377→        toolUseId: m.toolUseId,
   378→        parentToolUseId: m.parentToolUseId,
   379→        data: JSON.parse(m.data) as unknown,
   380→      })));
   381→    } catch (err) {
   382→      res.status(500).json({ error: String(err) });
   383→    }
   384→  });
   385→
   386→  // ─── V2 helpers ─────────────────────────────────────────────────────────────
   387→
   388→  type V2Session = {
   389→    summary: {
   390→      intent: string; outcome: string;
   391→      openItems: { id: number; text: string; status: string; subSessionId: string | null }[];
   392→      frictionItems: { text: string }[];
   393→      repoLearnings: { text: string }[];
   394→      codeLearnings: { path: string; finding: string }[];
   395→      workflowLearnings: { text: string }[];
   396→    } | null;
   397→  };
   398→
   399→  function mapV2Summary(summary: NonNullable<V2Session["summary"]>) {
   400→    return {
   401→      intent:            summary.intent,
   402→      outcome:           summary.outcome,
   403→      openItems:         summary.openItems.map((r) => ({ id: r.id, text: r.text, status: r.status, subSessionId: r.subSessionId })),
   404→      friction:          summary.frictionItems.map((r) => r.text),
   405→      repoLearnings:     summary.repoLearnings.map((r) => r.text),
   406→      codeLearnings:     summary.codeLearnings.map((r) => ({ path: r.path, finding: r.finding })),
   407→      workflowLearnings: summary.workflowLearnings.map((r) => r.text),
   408→    };
   409→  }
   410→
   411→  const V2_SESSION_INCLUDE = {
   412→    summary: {
   413→      include: {
   414→        openItems:         true,
   415→        frictionItems:     true,
   416→        repoLearnings:     true,
   417→        codeLearnings:     true,
   418→        workflowLearnings: true,
   419→      },
   420→    },
   421→  } as const;
   422→
   423→  const V2_SESSION_ORDER = { createdAt: "desc" as const };
   424→
   425→  // GET /api/v2/checkpoints
   426→  app.get("/api/v2/checkpoints", async (_req, res) => {
   427→    try {
   428→      const checkpoints = await db.checkpointMetadata.findMany({
   429→        include: {
   430→          tokenUsage: true,
   431→          filesTouched: { include: { filePath: true } },
   432→        },
   433→      });
   434→
   435→      const checkpointIds = checkpoints.map((c) => c.checkpointId);
   436→
   437→      const sessions = await db.checkpointSessionMetadata.findMany({
   438→        where:   { checkpointId: { in: checkpointIds } },
   439→        orderBy: V2_SESSION_ORDER,
   440→        include: V2_SESSION_INCLUDE,
   441→      });
   442→
   443→      // Group sessions by checkpointId
   444→      const sessionsByCheckpoint = new Map<string, typeof sessions>();
   445→      for (const s of sessions) {
   446→        const arr = sessionsByCheckpoint.get(s.checkpointId) ?? [];
   447→        arr.push(s);
   448→        sessionsByCheckpoint.set(s.checkpointId, arr);
   449→      }
   450→
   451→      res.json(checkpoints.map((c) => {
   452→        const cpSessions = sessionsByCheckpoint.get(c.checkpointId) ?? [];
   453→        const summary = cpSessions.find((s) => s.summary)?.summary ?? null;
   454→        const latestCreatedAt = cpSessions
   455→          .filter((s): s is typeof s & { createdAt: Date } => s.createdAt !== null)
   456→          .map((s) => s.createdAt)
   457→          .sort((a, b) => b.getTime() - a.getTime())[0] ?? null;
   458→        return {
   459→          id:               c.id,
   460→          checkpointId:     c.checkpointId,
   461→          cliVersion:       c.cliVersion,
   462→          strategy:         c.strategy,
   463→          branch:           c.branch,
   464→          checkpointsCount: c.checkpointsCount,
   465→          createdAt:        latestCreatedAt?.toISOString() ?? null,
   466→          tokenUsage: c.tokenUsage ? {
   467→            inputTokens:         c.tokenUsage.inputTokens,
   468→            cacheCreationTokens: c.tokenUsage.cacheCreationTokens,
   469→            cacheReadTokens:     c.tokenUsage.cacheReadTokens,
   470→            outputTokens:        c.tokenUsage.outputTokens,
   471→            apiCallCount:        c.tokenUsage.apiCallCount,
   472→          } : null,
   473→          filesTouched:  c.filesTouched.map((f) => f.filePath.path),
   474→          sessionCount:  cpSessions.length,
   475→          summary: summary ? mapV2Summary(summary) : null,
   476→        };
   477→      }));
   478→    } catch (err) {
   479→      res.status(500).json({ error: String(err) });
   480→    }
   481→  });
   482→
   483→  // GET /api/v2/checkpoints/:id
   484→  app.get("/api/v2/checkpoints/:id", async (req, res) => {
   485→    try {
   486→      const checkpointId = req.params.id;
   487→      const checkpoint = await db.checkpointMetadata.findUnique({
   488→        where: { checkpointId },
   489→        include: {
   490→          tokenUsage: true,
   491→          filesTouched: { include: { filePath: true } },
   492→        },
   493→      });
   494→      if (!checkpoint) { res.status(404).json({ error: "Not found" }); return; }
   495→
   496→      const sessions = await db.checkpointSessionMetadata.findMany({
   497→        where:   { checkpointId },
   498→        orderBy: V2_SESSION_ORDER,
   499→        include: V2_SESSION_INCLUDE,
   500→      });
   501→
   502→      const summary = sessions.find((s) => s.summary)?.summary ?? null;
   503→
   504→      res.json({
   505→        id:               checkpoint.id,
   506→        checkpointId:     checkpoint.checkpointId,
   507→        cliVersion:       checkpoint.cliVersion,
   508→        strategy:         checkpoint.strategy,
   509→        branch:           checkpoint.branch,
   510→        checkpointsCount: checkpoint.checkpointsCount,
   511→        tokenUsage: checkpoint.tokenUsage ? {
   512→          inputTokens:         checkpoint.tokenUsage.inputTokens,
   513→          cacheCreationTokens: checkpoint.tokenUsage.cacheCreationTokens,
   514→          cacheReadTokens:     checkpoint.tokenUsage.cacheReadTokens,
   515→          outputTokens:        checkpoint.tokenUsage.outputTokens,
   516→          apiCallCount:        checkpoint.tokenUsage.apiCallCount,
   517→        } : null,
   518→        filesTouched:  checkpoint.filesTouched.map((f) => f.filePath.path),
   519→        sessionCount:  sessions.length,
   520→        summary:       summary ? mapV2Summary(summary) : null,
   521→      });
   522→    } catch (err) {
   523→      res.status(500).json({ error: String(err) });
   524→    }
   525→  });
   526→
   527→  // GET /api/v2/sessions/:id/checkpoints
   528→  app.get("/api/v2/sessions/:id/checkpoints", async (req, res) => {
   529→    try {
   530→      const sessionId = req.params.id;
   531→      const sessionRows = await db.checkpointSessionMetadata.findMany({
   532→        where:   { sessionId },
   533→        orderBy: { createdAt: "asc" },
   534→        include: {
   535→          ...V2_SESSION_INCLUDE,
   536→          tokenUsage:   true,
   537→          filesTouched: { include: { filePath: true } },
   538→        },
   539→      });
   540→
   541→      res.json(sessionRows.map((s) => ({
   542→        checkpointId: s.checkpointId,
   543→        cliVersion:   s.cliVersion,
   544→        branch:       s.branch,
   545→        createdAt:    s.createdAt?.toISOString() ?? null,
   546→        tokenUsage:   s.tokenUsage ? {
   547→          inputTokens:         s.tokenUsage.inputTokens,
   548→          cacheCreationTokens: s.tokenUsage.cacheCreationTokens,
   549→          cacheReadTokens:     s.tokenUsage.cacheReadTokens,
   550→          outputTokens:        s.tokenUsage.outputTokens,
   551→          apiCallCount:        s.tokenUsage.apiCallCount,
   552→        } : null,
   553→        filesTouched: s.filesTouched.map((f) => f.filePath.path),
