   658→        // Prune stale worktree registration first, then re-add
   659→        execSync(`git -C ${JSON.stringify(repoDir)} worktree prune`, { stdio: "pipe" });
   660→        execSync(
   661→          `git -C ${JSON.stringify(repoDir)} worktree add ${JSON.stringify(WORKTREE_PATH)} ${CHECKPOINT_BRANCH}`,
   662→          { stdio: "pipe" },
