   665→      } catch (err) {
   666→        process.stderr.write(`checkpoint indexer: failed to create worktree — ${err}\n`);
   667→      }
   668→    }
   669→
   670→    const runIndex = async () => {
   671→      if (!existsSync(WORKTREE_PATH)) return;
   672→      try {
   673→        // Pull latest commits into the worktree working tree
   674→        execSync(`git -C ${JSON.stringify(WORKTREE_PATH)} reset --hard HEAD`, { stdio: "pipe" });
   675→      } catch { /* non-fatal */ }
   676→      try {
   677→        const { newMessages } = await indexAllCheckpoints(db, WORKTREE_PATH);
   678→        if (newMessages > 0) {
   679→          process.stderr.write(`checkpoint indexer: +${newMessages} new messages\n`);
   680→          broadcast();
   681→        }
   682→      } catch { /* non-fatal */ }
   683→      try {
   684→        const { checkpoints } = await indexAllCheckpointsV2(db, WORKTREE_PATH);
   685→        if (checkpoints > 0) {
   686→          process.stderr.write(`checkpoint indexer v2: indexed ${checkpoints} checkpoints\n`);
   687→          broadcast();
   688→        }
   689→      } catch { /* non-fatal */ }
   690→    };
   691→
   692→    void runIndex();
   693→    checkpointPoller = setInterval(runIndex, 30_000);
   694→    process.stderr.write(`checkpoint indexer: polling every 30s (worktree: ${WORKTREE_PATH})\n`);
   695→  }
