    32→function groupClaudeTurns(items: DisplayItem[]): RenderItem[] {
    33→  const result: RenderItem[] = [];
    34→  let i = 0;
    35→  while (i < items.length) {
    36→    const item = items[i];
    37→    if (item.kind === "toolGroup") {
    38→      const toolGroups: ToolUseData[][] = [];
    39→      while (i < items.length && items[i].kind === "toolGroup") {
