    43→      let stop: Event | null = null;
    44→      if (i < items.length && items[i].kind === "event" && (items[i] as { kind: "event"; event: Event }).event.event === "Stop") {
    45→        stop = (items[i] as { kind: "event"; event: Event }).event;
    46→        i++;
