   118→export function SessionTree() {
   119→  const navigate = useNavigate();
   120→  const [sessions, setSessions] = useState<Session[]>([]);
   121→  const [loading, setLoading] = useState(true);
   122→  const [error, setError] = useState<string | null>(null);
   123→  const [expanded, setExpanded] = useState<Set<string>>(new Set());
   124→
   125→  const load = useCallback(async () => {
   126→    try {
   127→      const data = await fetchSessions();
   128→      setSessions(data);
   129→      setError(null);
   130→      setExpanded((prev) => {
   131→        const next = new Set(prev);
   132→        const parentIds = new Set(data.map((sess) => sess.parentSessionId).filter(Boolean));
   133→        for (const id of parentIds) if (id) next.add(id);
   134→        return next;
   135→      });
   136→    } catch (e) {
   137→      setError(String(e));
   138→    }
   139→  }, []);
   140→
   141→  useEffect(() => {
   142→    load().finally(() => setLoading(false));
   143→    return subscribeToUpdates(() => { load().catch(() => undefined); });
   144→  }, [load]);
   145→
   146→  const childMap = useMemo(() => buildChildMap(sessions), [sessions]);
   147→  const nodes = useMemo(() => {
   148→    const out: FlatNode[] = [];
   149→    flatten(null, childMap, 0, expanded, out);
   150→    return out;
   151→  }, [childMap, expanded]);
   152→
   153→  function toggle(sessionId: string) {
   154→    setExpanded((prev) => {
   155→      const next = new Set(prev);
   156→      if (next.has(sessionId)) next.delete(sessionId);
   157→      else next.add(sessionId);
   158→      return next;
   159→    });
   160→  }
   161→
   162→  if (loading) return <Center style={{ flex: 1 }}><Loader size="md" color="indigo" /></Center>;
   163→  if (error) return <Center style={{ flex: 1 }}><Text c="red">{error}</Text></Center>;
   164→  if (nodes.length === 0) return <Center style={{ flex: 1 }}><Text c="dimmed" size="sm">No sessions yet.</Text></Center>;
   165→
   166→  return (
   167→    <ScrollArea style={{ flex: 1 }}>
   168→      {nodes.map((node) => (
   169→        <div key={node.session.sessionId} style={{ position: "relative" }}>
   170→          {node.depth > 0 && (
   171→            <div style={{
   172→              position: "absolute",
   173→              top: 0,
   174→              left: 12 + (node.depth - 1) * INDENT + 9,
   175→              width: 1,
   176→              height: "100%",
   177→              backgroundColor: "var(--mantine-color-gray-3)",
   178→            }} />
   179→          )}
   180→          <TreeNode
   181→            node={node}
   182→            isExpanded={expanded.has(node.session.sessionId)}
   183→            onPress={() =>
   184→              navigate(`/sessions/${node.session.sessionId}`, {
   185→                state: { title: node.session.summary ?? node.session.sessionId.slice(0, 8) + "…" },
   186→              })
   187→            }
   188→            onToggle={() => toggle(node.session.sessionId)}
   189→          />
   190→        </div>
   191→      ))}
   192→    </ScrollArea>
   193→  );
   194→}
