     6→const BRANCH_COLORS = ["indigo", "teal", "orange", "red", "violet", "cyan", "pink"] as const;
     7→type BranchColor = typeof BRANCH_COLORS[number];
     8→
     9→function branchColor(branch: string | null): BranchColor {
    10→  if (!branch) return "indigo";
    11→  let hash = 0;
    12→  for (let i = 0; i < branch.length; i++) hash = (hash * 31 + branch.charCodeAt(i)) >>> 0;
    13→  return BRANCH_COLORS[hash % BRANCH_COLORS.length];
    14→}
