    23→    try {
    24→      const data = await fetchCheckpoints();
    25→      setCheckpoints([...data].sort((a, b) => a.id - b.id));
    26→      setError(null);
    27→    } catch (err) {
    28→      setError(String(err));
    29→    }
    30→  }, []);
    31→
    32→  useEffect(() => {
    33→    load().finally(() => setLoading(false));
    34→    return subscribeToUpdates(() => { load().catch(() => undefined); });
    35→  }, [load]);
    36→
    37→  if (loading) return <Center style={{ flex: 1 }}><Loader size="md" color="teal" /></Center>;
    38→  if (error) return <Center style={{ flex: 1, padding: 24 }}><Alert color="red" title="Error" maw={480}>{error}</Alert></Center>;
    39→  if (checkpoints.length === 0) return <Center style={{ flex: 1 }}><Text c="dimmed" size="sm">No checkpoints indexed yet.</Text></Center>;
    40→
    41→  return (
    42→    <ScrollArea style={{ flex: 1 }} p="md">
    43→      <Timeline active={checkpoints.length - 1} bulletSize={16} lineWidth={2} pl="sm">
    44→        {checkpoints.map((cp) => {
    45→          const color = branchColor(cp.branch);
    46→          const outTokens = cp.tokenUsage?.outputTokens ?? 0;
    47→          const fileCount = cp.filesTouched.length;
    48→          return (
    49→            <Timeline.Item
    50→              key={cp.checkpointId}
    51→              color={color}
    52→              title={
    53→                <Group gap={8} wrap="wrap" mb={2}>
    54→                  {cp.branch && <Badge variant="light" color={color} size="sm">{cp.branch}</Badge>}
    55→                  <Text ff="monospace" size="xs" fw={600}>{cp.checkpointId}</Text>
    56→                </Group>
    57→              }
    58→              onClick={() =>
    59→                navigate(`/checkpoints/${cp.checkpointId}`, {
    60→                  state: { title: cp.branch ? `${cp.branch} · ${cp.checkpointId}` : cp.checkpointId },
    61→                })
    62→              }
    63→              style={{ cursor: "pointer" }}
    64→            >
    65→              {cp.summary?.intent && (
    66→                <Text size="xs" c="dimmed" fs="italic" mb={4}>{cp.summary.intent}</Text>
    67→              )}
    68→              <Group gap={12}>
    69→                {fileCount > 0 && <Text size="xs" c="dimmed" ff="monospace">{fileCount} file{fileCount !== 1 ? "s" : ""}</Text>}
    70→                {outTokens > 0 && <Text size="xs" c="dimmed" ff="monospace">{outTokens.toLocaleString()} tok</Text>}
    71→                {cp.sessionCount > 0 && <Text size="xs" c="dimmed" ff="monospace">{cp.sessionCount} session{cp.sessionCount !== 1 ? "s" : ""}</Text>}
    72→              </Group>
    73→            </Timeline.Item>
    74→          );
    75→        })}
    76→      </Timeline>
    77→    </ScrollArea>
    78→  );
    79→}
