    23→function activityDot(updatedAt: string): { color: string; label: string } {
    24→  const diff = Date.now() - new Date(updatedAt).getTime();
    25→  if (diff < 2 * 60 * 1000)  return { color: "var(--mantine-color-green-6)", label: "Active" };
    26→  if (diff < 15 * 60 * 1000) return { color: "var(--mantine-color-yellow-6)", label: "Idle" };
    27→  return { color: "light-dark(var(--mantine-color-gray-4), var(--mantine-color-dark-3))", label: "Inactive" };
    28→}
    29→
    30→interface CopyCellProps {
    31→  copyValue: string;
    32→  width: number;
    33→  children: React.ReactNode;
    34→  prefix?: React.ReactNode;
    35→}
    36→
    37→function CopyCell({ copyValue, width, children, prefix }: CopyCellProps) {
    38→  const [hovered, setHovered] = useState(false);
    39→  const [copied, setCopied] = useState(false);
    40→
    41→  function copy(e: React.MouseEvent) {
    42→    e.stopPropagation();
    43→    navigator.clipboard.writeText(copyValue).catch(() => undefined);
    44→    setCopied(true);
    45→    setTimeout(() => setCopied(false), 1200);
    46→  }
    47→
    48→  return (
    49→    <Table.Td
    50→      onMouseEnter={() => setHovered(true)}
    51→      onMouseLeave={() => { setHovered(false); setCopied(false); }}
    52→      style={{ width, maxWidth: width, overflow: "hidden", position: "relative", paddingRight: hovered ? 28 : undefined }}
    53→    >
    54→      <div style={{ display: "flex", alignItems: "center", gap: 6, overflow: "hidden" }}>
    55→        {prefix}
    56→        <div style={{ overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap", flex: 1 }}>
    57→          {children}
    58→        </div>
    59→      </div>
    60→      {hovered && copyValue && (
    61→        <Tooltip label={copied ? "Copied!" : "Copy"} withArrow position="top" openDelay={0}>
    62→          <ActionIcon
    63→            size="xs"
    64→            variant="subtle"
    65→            color={copied ? "green" : "gray"}
    66→            onClick={copy}
    67→            style={{ position: "absolute", right: 4, top: "50%", transform: "translateY(-50%)" }}
    68→          >
    69→            {copied ? "✓" : "⧉"}
    70→          </ActionIcon>
    71→        </Tooltip>
    72→      )}
    73→    </Table.Td>
    74→  );
    75→}
