     1→import React, { useState } from "react";
     2→import { Tooltip, Text } from "@mantine/core";
     3→
     4→export function relativeTime(iso: string): string {
     5→  const diff = Date.now() - new Date(iso).getTime();
     6→  const secs = Math.floor(diff / 1000);
     7→  if (secs < 60) return "just now";
     8→  const mins = Math.floor(secs / 60);
     9→  if (mins < 60) return `${mins}m ago`;
    10→  const hours = Math.floor(mins / 60);
    11→  if (hours < 24) return `${hours}h ago`;
    12→  const days = Math.floor(hours / 24);
    13→  if (days < 30) return `${days}d ago`;
    14→  const months = Math.floor(days / 30);
    15→  if (months < 12) return `${months}mo ago`;
    16→  return `${Math.floor(months / 12)}y ago`;
    17→}
    18→
    19→export function absoluteTime(iso: string): string {
    20→  return new Date(iso).toLocaleString();
    21→}
    22→
    23→interface Props {
    24→  iso: string;
    25→  size?: string;
    26→}
    27→
    28→export function TimeAgo({ iso, size = "xs" }: Props) {
    29→  const [copied, setCopied] = useState(false);
    30→  const abs = absoluteTime(iso);
    31→
    32→  function copy(e: React.MouseEvent) {
    33→    e.stopPropagation();
    34→    navigator.clipboard.writeText(abs).catch(() => undefined);
    35→    setCopied(true);
    36→    setTimeout(() => setCopied(false), 1500);
    37→  }
    38→
    39→  return (
    40→    <Tooltip label={copied ? "Copied!" : abs} withArrow openDelay={200}>
    41→      <Text
    42→        component="span"
    43→        size={size as never}
    44→        c="dimmed"
    45→        style={{ cursor: "pointer" }}
    46→        onClick={copy}
    47→      >
    48→        {relativeTime(iso)}
    49→      </Text>
    50→    </Tooltip>
    51→  );
    52→}
