        <Text size="xs" c="dimmed">{open ? "▲" : "▼"}</Text>
      </UnstyledButton>
      <Collapse in={open}>
        {items.map((item, i) => (
          <Box key={i} pl={8} mb={4}>
            <Text size="xs" ff="monospace" c="violet" fw={600}>{item.path}</Text>
            <Text size="xs" c="dimmed">{item.finding}</Text>
          </Box>
        ))}
      </Collapse>
    </Box>
  );
}

