    42→  sessionId: string;
    43→  summary: string;
    44→  keywords: string[];
    45→  startedAt: string;
    46→  endedAt: string;
    47→}
    48→
    49→// ─── Mapping helpers ──────────────────────────────────────────────────────────
    50→
    51→function mapSummary(s: {
    52→  intent: string;
    53→  outcome: string;
    54→  learningsRepo: string | null;
    55→  learningsCode: string | null;
    56→  learningsWorkflow: string | null;
    57→  friction: string | null;
    58→  openItems: string | null;
    59→}) {
    60→  return {
    61→    intent: s.intent,
    62→    outcome: s.outcome,
    63→    repoLearnings:     s.learningsRepo     ? (JSON.parse(s.learningsRepo)     as string[]) : [],
    64→    codeLearnings:     s.learningsCode     ? (JSON.parse(s.learningsCode)     as Array<{ path: string; finding: string }>) : [],
    65→    workflowLearnings: s.learningsWorkflow ? (JSON.parse(s.learningsWorkflow) as string[]) : [],
    66→    friction:          s.friction          ? (JSON.parse(s.friction)          as string[]) : [],
