// ─── Response types ───────────────────────────────────────────────────────────

interface SessionResponse {
  sessionId: string;
  startedAt: string;
  updatedAt: string;
  cwd: string;
  repoRoot: string | null;
  repoName: string | null;
  parentSessionId: string | null;
  childSessionIds: string[];
  gitUserName: string | null;
  gitUserEmail: string | null;
  prompt: string | null;
  summary: string | null;
  keywords: string[];
  branch: string | null;
  intent: string | null;
}

interface EventResponse {
  id: number;
  timestamp: string;
  event: string;
  sessionId: string;
  blocked: boolean;
  data: unknown;
  summary: string | null;
  keywords: string[];
}

interface OverviewResponse {
  sessionId: string;
  summary: string;
  keywords: string[];
  startedAt: string;
  endedAt: string;
}

// ─── Mapping helpers ──────────────────────────────────────────────────────────

function mapSummary(s: {
  intent: string;
  outcome: string;
  learningsRepo: string | null;
  learningsCode: string | null;
  learningsWorkflow: string | null;
  friction: string | null;
  openItems: string | null;
}) {
  return {
    intent: s.intent,
    outcome: s.outcome,
    repoLearnings:     s.learningsRepo     ? (JSON.parse(s.learningsRepo)     as string[]) : [],
    codeLearnings:     s.learningsCode     ? (JSON.parse(s.learningsCode)     as Array<{ path: string; finding: string }>) : [],
    workflowLearnings: s.learningsWorkflow ? (JSON.parse(s.learningsWorkflow) as string[]) : [],
    friction:          s.friction          ? (JSON.parse(s.friction)          as string[]) : [],
    openItems:         s.openItems         ? (JSON.parse(s.openItems)         as string[]) : [],
  };
}


function mapSession(
  s: {
    sessionId: string;
    startedAt: Date;
    updatedAt: Date;
    cwd: string;
    repoRoot: string | null;
    repoName: string | null;
    parentSessionId: string | null;
    gitUserName: string | null;
    gitUserEmail: string | null;
    prompt: string | null;
    summary: string | null;
    keywords: string | null;
  },
  childSessionIds: string[] = [],
  branch: string | null = null,
  intent: string | null = null,
): SessionResponse {
  return {
    sessionId: s.sessionId,
    startedAt: s.startedAt.toISOString(),
    updatedAt: s.updatedAt.toISOString(),
    cwd: s.cwd,
    repoRoot: s.repoRoot,
    repoName: s.repoName,
    parentSessionId: s.parentSessionId,
    childSessionIds,
    gitUserName: s.gitUserName,
    gitUserEmail: s.gitUserEmail,
    prompt: s.prompt,
    summary: s.summary,
    keywords: s.keywords ? (JSON.parse(s.keywords) as string[]) : [],
    branch,
    intent,
  };
}

function mapEvent(e: {
  id: number;
  timestamp: Date;
  event: string;
  sessionId: string;
  blocked: boolean;
  data: string;
  summary: string | null;
  keywords: string | null;
}): EventResponse {
  let parsedData: unknown;
  try {
    parsedData = JSON.parse(e.data);
  } catch {
    parsedData = e.data;
  }
  return {
    id: e.id,
    timestamp: e.timestamp.toISOString(),
    event: e.event,
    sessionId: e.sessionId,
    blocked: e.blocked,
    data: parsedData,
    summary: e.summary,
    keywords: e.keywords ? (JSON.parse(e.keywords) as string[]) : [],
  };
}

// ─── Server ───────────────────────────────────────────────────────────────────

export async function startServer(dbPath: string, port: number, repoDir?: string): Promise<void> {
  // Strip CLAUDECODE so spawned sessions are not blocked by nested-session detection
  delete process.env.CLAUDECODE;

  const db = await getDb(dbPath);

  const app = express();
  app.use(cors());
  app.use(express.json());

