}

const COMPACT_COLOR = "light-dark(var(--mantine-color-gray-6), var(--mantine-color-gray-4))";
const TYPE_STYLE: Record<string, { sym: string; color: string }> = {
  progress: { sym: "◆", color: COMPACT_COLOR },
